<template>
  <div class="user-statistics-container">
    <el-card class="filter-container">
      <div slot="header" class="clearfix">
        <span>用户分析</span>
      </div>
      
      <el-form :inline="true" :model="filterForm" class="filter-form">
        <el-form-item label="时间范围">
          <el-date-picker
            v-model="filterForm.dateRange"
            type="daterange"
            range-separator="至"
            start-placeholder="开始日期"
            end-placeholder="结束日期"
            value-format="yyyy-MM-dd"
            :picker-options="pickerOptions">
          </el-date-picker>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="fetchData">查询</el-button>
          <el-button @click="exportData" icon="el-icon-download">导出</el-button>
        </el-form-item>
      </el-form>
    </el-card>
    
    <div class="data-overview">
      <el-row :gutter="20">
        <el-col :span="6">
          <el-card shadow="hover" class="data-card">
            <div slot="header" class="clearfix">
              <span>用户总数</span>
            </div>
            <div class="data-card-content">
              <div class="data-value">{{ formatNumber(overviewData.totalUsers) }}</div>
              <div class="data-compare" :class="overviewData.userGrowth >= 0 ? 'positive' : 'negative'">
                <i :class="overviewData.userGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                {{ Math.abs(overviewData.userGrowth) }}% 较上期
              </div>
            </div>
          </el-card>
        </el-col>
        <el-col :span="6">
          <el-card shadow="hover" class="data-card">
            <div slot="header" class="clearfix">
              <span>新增用户</span>
            </div>
            <div class="data-card-content">
              <div class="data-value">{{ formatNumber(overviewData.newUsers) }}</div>
              <div class="data-compare" :class="overviewData.newUserGrowth >= 0 ? 'positive' : 'negative'">
                <i :class="overviewData.newUserGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                {{ Math.abs(overviewData.newUserGrowth) }}% 较上期
              </div>
            </div>
          </el-card>
        </el-col>
        <el-col :span="6">
          <el-card shadow="hover" class="data-card">
            <div slot="header" class="clearfix">
              <span>活跃用户</span>
            </div>
            <div class="data-card-content">
              <div class="data-value">{{ formatNumber(overviewData.activeUsers) }}</div>
              <div class="data-compare" :class="overviewData.activeUserGrowth >= 0 ? 'positive' : 'negative'">
                <i :class="overviewData.activeUserGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                {{ Math.abs(overviewData.activeUserGrowth) }}% 较上期
              </div>
            </div>
          </el-card>
        </el-col>
        <el-col :span="6">
          <el-card shadow="hover" class="data-card">
            <div slot="header" class="clearfix">
              <span>客单价</span>
            </div>
            <div class="data-card-content">
              <div class="data-value">¥ {{ formatNumber(overviewData.averageOrderValue) }}</div>
              <div class="data-compare" :class="overviewData.aovGrowth >= 0 ? 'positive' : 'negative'">
                <i :class="overviewData.aovGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                {{ Math.abs(overviewData.aovGrowth) }}% 较上期
              </div>
            </div>
          </el-card>
        </el-col>
      </el-row>
    </div>
    
    <el-row :gutter="20" class="chart-row">
      <el-col :span="12">
        <el-card class="chart-card">
          <div slot="header" class="clearfix">
            <span>用户增长趋势</span>
          </div>
          <div id="userGrowthChart" style="width: 100%; height: 350px;"></div>
        </el-card>
      </el-col>
      <el-col :span="12">
        <el-card class="chart-card">
          <div slot="header" class="clearfix">
            <span>用户地域分布</span>
          </div>
          <div id="userRegionChart" style="width: 100%; height: 350px;"></div>
        </el-card>
      </el-col>
    </el-row>
    
    <el-row :gutter="20" class="chart-row">
      <el-col :span="12">
        <el-card class="chart-card">
          <div slot="header" class="clearfix">
            <span>用户年龄分布</span>
          </div>
          <div id="userAgeChart" style="width: 100%; height: 350px;"></div>
        </el-card>
      </el-col>
      <el-col :span="12">
        <el-card class="chart-card">
          <div slot="header" class="clearfix">
            <span>用户消费分布</span>
          </div>
          <div id="userSpendChart" style="width: 100%; height: 350px;"></div>
        </el-card>
      </el-col>
    </el-row>
    
    <el-card class="table-card">
      <div slot="header" class="clearfix">
        <span>用户价值排行</span>
      </div>
      
      <el-table
        :data="userValueList"
        style="width: 100%"
        border
        v-loading="loading">
        <el-table-column
          type="index"
          label="排名"
          width="80">
        </el-table-column>
        <el-table-column
          prop="username"
          label="用户名"
          width="180">
        </el-table-column>
        <el-table-column
          prop="phone"
          label="手机号"
          width="150">
        </el-table-column>
        <el-table-column
          prop="orderCount"
          label="订单数"
          sortable
          width="120">
        </el-table-column>
        <el-table-column
          prop="totalSpend"
          label="消费总额"
          sortable
          width="150">
          <template slot-scope="scope">
            ¥ {{ formatNumber(scope.row.totalSpend) }}
          </template>
        </el-table-column>
        <el-table-column
          prop="averageOrderValue"
          label="平均客单价"
          sortable
          width="150">
          <template slot-scope="scope">
            ¥ {{ formatNumber(scope.row.averageOrderValue) }}
          </template>
        </el-table-column>
        <el-table-column
          prop="lastOrderTime"
          label="最近下单时间"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作"
          width="100">
          <template slot-scope="scope">
            <el-button @click="viewUserDetails(scope.row.id)" type="text" size="small">查看详情</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!loading && userValueList.length === 0" description="暂无数据" />
      
      <div class="pagination-container">
        <el-pagination
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="pagination.currentPage"
          :page-sizes="[10, 20, 50, 100]"
          :page-size="pagination.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="pagination.total">
        </el-pagination>
      </div>
    </el-card>
  </div>
</template>

<script>
import * as echarts from 'echarts'
 // import 'echarts/map/js/china'
import statisticsApi from '@/api/statistics'

export default {
  name: 'UserStatistics',
  data() {
    return {
      filterForm: {
        dateRange: [this.getLastMonthDate(), this.formatDate(new Date())]
      },
      pickerOptions: {
        shortcuts: [
          {
            text: '最近一周',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 7)
              picker.$emit('pick', [start, end])
            }
          },
          {
            text: '最近一个月',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 30)
              picker.$emit('pick', [start, end])
            }
          },
          {
            text: '最近三个月',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 90)
              picker.$emit('pick', [start, end])
            }
          }
        ]
      },
      overviewData: {
        totalUsers: 0,
        userGrowth: 0,
        newUsers: 0,
        newUserGrowth: 0,
        activeUsers: 0,
        activeUserGrowth: 0,
        averageOrderValue: 0,
        aovGrowth: 0
      },
      userValueList: [],
      loading: false,
      userGrowthChart: null,
      userRegionChart: null,
      userAgeChart: null,
      userSpendChart: null,
      pagination: {
        currentPage: 1,
        pageSize: 10,
        total: 0
      }
    }
  },
  mounted() {
    this.fetchData()
    window.addEventListener('resize', this.resizeCharts)
  },
  beforeDestroy() {
    window.removeEventListener('resize', this.resizeCharts)
    this.disposeCharts()
  },
  methods: {
    formatDate(date) {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      return `${year}-${month}-${day}`
    },
    getLastMonthDate() {
      const date = new Date()
      date.setMonth(date.getMonth() - 1)
      return this.formatDate(date)
    },
    formatNumber(num) {
      if (num === undefined || num === null) return '0.00'
      return num.toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    },
    async fetchData() {
      this.loading = true
      try {
        const params = {
          startDate: this.filterForm.dateRange[0],
          endDate: this.filterForm.dateRange[1]
        }
        
        const response = await statisticsApi.getUserGrowth(params)
        
        if (response.code === 0 && response.data) {
          // 更新概览数据
          this.overviewData = response.data.overview
          
          // 初始化图表
          this.initUserGrowthChart(response.data.userGrowthTrend)
          this.initUserRegionChart(response.data.userRegionDistribution)
          this.initUserAgeChart(response.data.userAgeDistribution)
          this.initUserSpendChart(response.data.userSpendDistribution)
          
          // 获取用户价值排行
          this.fetchUserValueList()
        } else {
          this.$message.error(response.message || '获取用户统计数据失败')
        }
      } catch (error) {
        console.error('获取用户统计数据出错:', error)
        this.$message.error('获取用户统计数据出错')
      } finally {
        this.loading = false
      }
    },
    async fetchUserValueList() {
      try {
        const params = {
          startDate: this.filterForm.dateRange[0],
          endDate: this.filterForm.dateRange[1],
          page: this.pagination.currentPage,
          pageSize: this.pagination.pageSize
        }
        
        const response = await statisticsApi.getUserGrowth()
        
        if (response.code === 0 && response.data) {
          this.userValueList = response.data.list
          this.pagination.total = response.data.total
        }
      } catch (error) {
        console.error('获取用户价值排行出错:', error)
        this.$message.error('获取数据失败，请稍后重试')
      }
    },
    initUserGrowthChart(data) {
      if (!data) return
      
      if (!this.userGrowthChart) {
        this.userGrowthChart = echarts.init(document.getElementById('userGrowthChart'))
      }
      
      const option = {
        tooltip: {
          trigger: 'axis',
          axisPointer: {
            type: 'cross',
            label: {
              backgroundColor: '#6a7985'
            }
          }
        },
        legend: {
          data: ['新增用户', '活跃用户', '总用户']
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          containLabel: true
        },
        xAxis: [
          {
            type: 'category',
            boundaryGap: false,
            data: data.dates
          }
        ],
        yAxis: [
          {
            type: 'value'
          }
        ],
        series: [
          {
            name: '新增用户',
            type: 'line',
            stack: '总量',
            areaStyle: {},
            emphasis: {
              focus: 'series'
            },
            data: data.newUsers
          },
          {
            name: '活跃用户',
            type: 'line',
            stack: '总量',
            areaStyle: {},
            emphasis: {
              focus: 'series'
            },
            data: data.activeUsers
          },
          {
            name: '总用户',
            type: 'line',
            stack: '总量',
            label: {
              show: true,
              position: 'top'
            },
            areaStyle: {},
            emphasis: {
              focus: 'series'
            },
            data: data.totalUsers
          }
        ]
      }
      
      this.userGrowthChart.setOption(option)
    },
       initUserRegionChart(data) {
     if (!data) return
     
     // 创建一个简单的柱状图代替地图
     if (!this.userRegionChart) {
       this.userRegionChart = echarts.init(document.getElementById('userRegionChart'))
     }
     
     // 提取地区名称和值
     const regions = data.map(item => item.name);
     const values = data.map(item => item.value);
     
     const option = {
       title: {
         text: '用户地域分布',
         left: 'center'
       },
       tooltip: {
         trigger: 'axis',
         axisPointer: {
           type: 'shadow'
         }
       },
       xAxis: {
         type: 'category',
         data: regions,
         axisLabel: {
           interval: 0,
           rotate: 45
         }
       },
       yAxis: {
         type: 'value'
       },
       series: [{
         data: values,
         type: 'bar'
       }]
     };
     
     this.userRegionChart.setOption(option)
   },
    initUserAgeChart(data) {
      if (!data) return
      
      if (!this.userAgeChart) {
        this.userAgeChart = echarts.init(document.getElementById('userAgeChart'))
      }
      
      const option = {
        tooltip: {
          trigger: 'item',
          formatter: '{a} <br/>{b}: {c} ({d}%)'
        },
        legend: {
          orient: 'vertical',
          left: 10,
          data: data.map(item => item.name)
        },
        series: [
          {
            name: '年龄分布',
            type: 'pie',
            radius: ['50%', '70%'],
            avoidLabelOverlap: false,
            label: {
              show: false,
              position: 'center'
            },
            emphasis: {
              label: {
                show: true,
                fontSize: '18',
                fontWeight: 'bold'
              }
            },
            labelLine: {
              show: false
            },
            data: data
          }
        ]
      }
      
      this.userAgeChart.setOption(option)
    },
    initUserSpendChart(data) {
      if (!data) return
      
      if (!this.userSpendChart) {
        this.userSpendChart = echarts.init(document.getElementById('userSpendChart'))
      }
      
      // 计算百分比
      const total = data.reduce((acc, curr) => acc + curr.value, 0)
      const dataWithPercentage = data.map(item => ({
        ...item,
        percentage: ((item.value / total) * 100).toFixed(2)
      }))
      
      const option = {
        tooltip: {
          trigger: 'item',
          formatter: '{a} <br/>{b}: {c} ({d}%)'
        },
        legend: {
          orient: 'vertical',
          left: 10,
          data: dataWithPercentage.map(item => item.name)
        },
        series: [
          {
            name: '消费分布',
            type: 'pie',
            radius: '55%',
            center: ['50%', '60%'],
            data: dataWithPercentage,
            emphasis: {
              itemStyle: {
                shadowBlur: 10,
                shadowOffsetX: 0,
                shadowColor: 'rgba(0, 0, 0, 0.5)'
              }
            }
          }
        ]
      }
      
      this.userSpendChart.setOption(option)
    },
    handleSizeChange(val) {
      this.pagination.pageSize = val
      this.fetchUserValueList()
    },
    handleCurrentChange(val) {
      this.pagination.currentPage = val
      this.fetchUserValueList()
    },
    viewUserDetails(id) {
      if (id) {
        this.$router.push(`/user/detail/${id}`)
      } else {
        this.$router.push('/user/list')
      }
    },
    resizeCharts() {
      if (this.userGrowthChart) {
        this.userGrowthChart.resize()
      }
      if (this.userRegionChart) {
        this.userRegionChart.resize()
      }
      if (this.userAgeChart) {
        this.userAgeChart.resize()
      }
      if (this.userSpendChart) {
        this.userSpendChart.resize()
      }
    },
    disposeCharts() {
      if (this.userGrowthChart) {
        this.userGrowthChart.dispose()
        this.userGrowthChart = null
      }
      if (this.userRegionChart) {
        this.userRegionChart.dispose()
        this.userRegionChart = null
      }
      if (this.userAgeChart) {
        this.userAgeChart.dispose()
        this.userAgeChart = null
      }
      if (this.userSpendChart) {
        this.userSpendChart.dispose()
        this.userSpendChart = null
      }
    },
    exportData() {
      this.$message({
        message: '数据导出功能正在开发中...',
        type: 'warning'
      })
    }
  }
}
</script>

<style lang="scss" scoped>
